function mergeWorldFromAnyShape(candidate: any): Record<string, unknown> {
  const sd = candidate?.stat_data;
  const inner = sd && typeof sd === 'object' && sd.stat_data && typeof sd.stat_data === 'object' ? sd.stat_data : null;
  const out: Record<string, unknown> = {
    ...(candidate || {}),
    ...(sd || {}),
    世界: {
      ...(sd?.世界 || {}),
      ...(inner?.世界 || {}),
      ...(candidate?.display_data?.世界 || {}),
      ...(candidate?.世界 || {}),
    },
  };
  return out;
}

function mergeHeroFromAnyShape(candidate: any): Record<string, unknown> {
  const sd = candidate?.stat_data;
  const inner = sd && typeof sd === 'object' && sd.stat_data && typeof sd.stat_data === 'object' ? sd.stat_data : null;
  const out: Record<string, unknown> = {
    ...(candidate || {}),
    ...(sd || {}),
    // 内层 stat_data.主角 多为 JSON Patch / MVU 实际写入层，应覆盖外层镜像，避免双份 主角 时读到旧风格或旧状态
    主角: {
      ...(sd?.主角 || {}),
      ...(inner?.主角 || {}),
      ...(candidate?.display_data?.主角 || {}),
      ...(candidate?.主角 || {}),
    },
  };
  return out;
}

function extractHeroValueFromAnyShape(candidate: any, key: string): unknown {
  const merged = mergeHeroFromAnyShape(candidate);
  return (merged as any)?.主角?.[key];
}

function getHeroValueByKeyRaw(key: string): unknown {
  try {
    const g = globalThis as any;
    if (g?.Mvu && typeof g.Mvu.getMvuData === 'function') {
      const byLatest = g.Mvu.getMvuData({ type: 'message', message_id: 'latest' });
      const raw = extractHeroValueFromAnyShape(byLatest, key);
      if (raw !== undefined) return raw;
    }
  } catch {
    /* ignore */
  }

  const scopes: Array<Parameters<typeof getVariables>[0]> = [
    { type: 'message', message_id: 'latest' },
    { type: 'chat' },
    { type: 'character' },
    { type: 'global' },
  ];
  for (const scope of scopes) {
    try {
      const v = getVariables(scope) as any;
      const raw = extractHeroValueFromAnyShape(v, key);
      if (raw !== undefined) return raw;
    } catch {
      /* ignore */
    }
  }
  return undefined;
}

