/**
 * MVU 可能写入过渡态字符串（如 `生活->战斗 (json_patch)`），不能仅用 `=== '战斗'`。
 * 取最后一个 `-> / → / => / /` 片段，去掉末尾 ` (…)` 后与「战斗」比较；避免用 includes 误伤「非战斗」。
 */
function normalizeHeroStatusForCombatCheck(raw: string): string {
  const t = raw.trim();
  if (!t) return '';
  const lastSeg = /(?:->|→|=>|\/)/.test(t)
    ? (t.split(/(?:->|→|=>|\/)/).pop() ?? t).trim()
    : t;
  return lastSeg.replace(/\s*\([^)]*\)\s*$/g, '').trim();
}

function isHeroInCombatFromStatus(raw: string): boolean {
  return normalizeHeroStatusForCombatCheck(raw) === '战斗';
}

