function debugGatherHeroStatusLayers(): Record<string, unknown> {
  const layers: Record<string, unknown> = {};
  const read = (prefix: string, candidate: any) => {
    if (!candidate || typeof candidate !== 'object') {
      layers[`${prefix}`] = candidate === undefined ? '(undefined)' : candidate;
      return;
    }
    layers[`${prefix}.stat_data.主角.状态`] = candidate?.stat_data?.主角?.状态;
    layers[`${prefix}.stat_data.stat_data.主角.状态`] = candidate?.stat_data?.stat_data?.主角?.状态;
    layers[`${prefix}.顶层.主角.状态`] = (candidate as any)?.主角?.状态;
  };
  try {
    const g = globalThis as any;
    if (g?.Mvu?.getMvuData) {
      read('Mvu.message.latest', g.Mvu.getMvuData({ type: 'message', message_id: 'latest' }));
    }
  } catch (e) {
    layers.Mvu_error = String(e);
  }
  const scopes: Array<Parameters<typeof getVariables>[0]> = [
    { type: 'message', message_id: 'latest' },
    { type: 'chat' },
    { type: 'character' },
    { type: 'global' },
  ];
  for (const scope of scopes) {
    try {
      const v = getVariables(scope) as any;
      const tag = `getVariables(${(scope as any).type}${(scope as any).message_id != null ? ',' + String((scope as any).message_id) : ''})`;
      read(tag, v);
    } catch (e) {
      layers[`getVariables_error_${JSON.stringify(scope)}`] = String(e);
    }
  }
  layers['mergeHeroFromAnyShape(latest Mvu)'] = (() => {
    try {
      const g = globalThis as any;
      if (g?.Mvu?.getMvuData) {
        return mergeHeroFromAnyShape(g.Mvu.getMvuData({ type: 'message', message_id: 'latest' }))?.主角?.状态;
      }
    } catch {
      /* ignore */
    }
    return undefined;
  })();
  layers.getHeroValueByKeyRaw_状态 = getHeroValueByKeyRaw('状态');
  layers.getHeroStatusRaw = getHeroStatusRaw();
  return layers;
}

/** 旧版「委托执行中」判定，仅用于与 heroInCombat 对比（调试） */
function debugQuestLegacySnapshot(): { hasQuestLegacy: boolean; questContentNorm: string; questStatusRaw: string } {
  const questContentRaw = getWorldTextByKey('当前委托内容');
  const questContent = normalizeWorldTextValue(questContentRaw);
  const questStatusKeys = ['委托状态', '当前委托状态', '委托执行状态'];
  const questStatusRaw =
    questStatusKeys.map(k => getWorldTextByKey(k)).find(v => Boolean(normalizeWorldTextValue(v))) ?? '';
  const t = normalizeWorldTextValue(questStatusRaw);
  let hasQuestLegacy = questContent.length > 0;
  if (!hasQuestLegacy) {
    if (t === '执行中') hasQuestLegacy = true;
    else if (t && !/结束|已完成|已结束|取消|失效/i.test(t) && /执行|进行中|承接|进行/i.test(t)) hasQuestLegacy = true;
  }
  return { hasQuestLegacy, questContentNorm: questContent, questStatusRaw };
}

