function normalizeWorldLocation(raw: string): string {
  let t = String(raw || '').trim();
  // 某些情况下世界.当前位置 会带 json_patch/箭头补丁等噪声
  // 例如：柳木镇·住宅区->暗月城·午夜玫瑰酒馆 (json_patch)
  t = t.replace(/\s*\(json_patch\)\s*$/i, '');
  // 取最后一个“->”右侧（代表最新落点）
  if (t.includes('->')) {
    const parts = t.split('->');
    t = String(parts[parts.length - 1] || '').trim();
  }
  // 去掉外围双引号
  t = t.replace(/^"+|"+$/g, '');
  return t.trim();
}

function normalizeWorldTextValue(raw: string): string {
  let t = String(raw || '').trim();
  t = t.replace(/\s*\(json_patch\)\s*$/i, '');
  if (t.includes('->')) {
    const parts = t.split('->');
    t = String(parts[parts.length - 1] || '').trim();
  }
  t = t.replace(/^"+|"+$/g, '');
  return t.trim();
}

function normalizeCombatStyleWord(style: string): string {
  // 兼容旧命名：皇家守卫 -> 皇家护卫
  if (style === '皇家守卫') return '皇家护卫';
  return style;
}

function normalizeTierToNumber(tierRaw: string): number | null {
  const t = String(tierRaw || '').trim();
  const map: Record<string, number> = {
    '1': 1,
    '2': 2,
    '3': 3,
    '4': 4,
    '１': 1,
    '２': 2,
    '３': 3,
    '４': 4,
    '一': 1,
    '二': 2,
    '三': 3,
    '四': 4,
  };
  const v = map[t];
  return typeof v === 'number' ? v : null;
}

type CombatStyleParsed = { style: string; tier: number };

function parseCombatStyleEntryName(entryName: string): CombatStyleParsed | null {
  const raw = String(entryName || '');
  const re = /(剑圣|枪神|骗术师|皇家护卫|皇家守卫)\s*风格\s*([1-4]|[１-４]|[一二三四])(?![0-9])/;
  const m = raw.match(re);
  if (!m) return null;
  const style = normalizeCombatStyleWord(m[1]);
  const tier = normalizeTierToNumber(m[2]);
  if (!tier) return null;
  return { style, tier };
}

function extractCurrentCombatStyleLabel(): string {
  const extractFromHero = (c: any): string => {
    if (!c || typeof c !== 'object') return '';

    // 1) 新字段：主角.战斗风格 直接存「xxx风格n」（例如：骗术师风格1）
    const styleRaw = c?.战斗风格;
    if (typeof styleRaw === 'string' && styleRaw.trim()) {
      const raw = styleRaw.trim();
      const parsed = parseCombatStyleEntryName(raw);
      if (parsed) return raw;

      // 兼容旧/简写：如果只给了「纯风格名」（如 剑圣 / 骗术师），则用 风格阶位 推导
      const normalizedStyle = normalizeCombatStyleWord(raw);
      const tierRaw = c?.风格阶位?.[normalizedStyle];
      if (typeof tierRaw === 'number' && tierRaw >= 1 && tierRaw <= 4) {
        return `${normalizedStyle}风格${Math.round(tierRaw)}`;
      }
      const tierNum = normalizeTierToNumber(String(tierRaw ?? ''));
      if (tierNum) return `${normalizedStyle}风格${tierNum}`;
    }

    // 2) 旧字段：主角.当前风格（历史兼容）
    if (typeof c?.当前风格 === 'string' && c?.当前风格.trim()) return c.当前风格.trim();

    return '';
  };

  const tryFrom = (v: any): string => {
    const candidates = [v?.主角, v?.stat_data?.主角, v?.mvu?.主角, v?.display_data?.主角].filter(Boolean);
    for (const c of candidates) {
      const s = extractFromHero(c);
      if (s) return s;
    }
    return '';
  };

  try {
    const g = globalThis as any;
    if (g?.Mvu && typeof g.Mvu.getMvuData === 'function') {
      // 注意：本脚本运行在“全局脚本 iframe”，禁止调用 getCurrentMessageId/getMessageId。
      // 因此这里仅安全读取 latest；即时性由下方优先读取 chat.stat_data 来保证（Dark 会镜像到 chat）。
      const latest = g.Mvu.getMvuData({ type: 'message', message_id: 'latest' });
      const s = tryFrom(latest);
      if (s) return s;
    }
  } catch {
    /* ignore */
  }

  const scopes: Array<Parameters<typeof getVariables>[0]> = [
    // 先读 chat.stat_data：Dark 会在写入后立即 mirror 到 chat，并派发 resync 事件（即时性最好）
    { type: 'chat' },
    // 再退回 latest/message/character/global
    { type: 'message', message_id: 'latest' },
    { type: 'character' },
    { type: 'global' },
  ];
  for (const scope of scopes) {
    try {
      const v = getVariables(scope) as any;
      const s = tryFrom(v);
      if (s) return s;
    } catch {
      /* ignore */
    }
  }
  return '';
}

