function shouldBlueHunterLevelByLastTwoMessages(): boolean {
  // 折中规则：只看「最近两楼里的那一条用户消息」
  // - 优先取最近两楼中标记为 user 的那一条（离现在最近的）
  // - 如果 user 标记全丢了，就把这两楼里的“前一楼”当成用户楼
  // - 判断这条候选用户楼：在安全地点 + 文本里有关键字 => 蓝灯，否则绿灯
  try {
    const worldLocation = getWorldLocation();
    const safePlaces = getQuestSettlementSafePlaces();
    const inSafePlace =
      safePlaces.length > 0 && worldLocation
        ? safePlaces.some(p => worldLocation.includes(p) || p.includes(worldLocation))
        : false;
    if (!inSafePlace) return false;

    const lastId = getLastMessageId();
    if (lastId < 0) return false;
    const all = getChatMessages(`0-${lastId}`);
    if (!all.length) return false;
    const recent = all.slice(Math.max(0, all.length - 2));
    if (!recent.length) return false;

    let candidate = undefined as any;
    // 1) 最近两楼里，优先找“最近的用户楼”
    for (let i = recent.length - 1; i >= 0; i--) {
      const m = recent[i];
      if (!messageIsUser(m)) continue;
      candidate = m;
      break;
    }

    // 2) 如果没有任何 user 标记，就退化：把“前一楼”当成用户楼（典型顺序：[用户, AI]）
    if (!candidate) {
      if (recent.length >= 2) candidate = recent[0];
      else candidate = recent[0];
    }

    if (!candidate) return false;
    const text = stripMessageNoise(String(candidate.message ?? '')).trim();
    return keywordHitInTexts([text], HUNTER_LEVEL_TRIGGER_USER_KEYWORDS);
  } catch {
    return false;
  }
}

