  const recentUserTexts = getRecentUserMessageTexts(SCAN_LAST_MESSAGES);
  const lastAnyText = getLastAnyMessageText();
  const lastTexts = lastAnyText ? [lastAnyText] : [];

  // 魔人化：检测“魔人化启动”并写入主角状态；DT 满 100 才允许进入魔人化
  const manjinRequested = shouldTriggerManjinByRecentTexts({ recentTexts, recentUserTexts, lastTexts });
