/**
 * 将误写在 stat_data 根节点下的「主角」字段收拢到 `主角` 对象内（与 Dark MVU schema 一致）。
 * 世界书 / 模型若用 _.set('状态', …) 或 JSON 补丁写到根上，会导致与 `主角.状态` 分裂。
 *
 * MVU 有时会出现 `stat_data.stat_data` 嵌套，导致「外层主角」与「内层主角」两套数据并存、风格/状态不一致。
 * `flattenNestedStatDataInStatData` 将内层合并进外层并删除嵌套键，只保留一份 `主角`。
 */

function deepMergeStatDataLayer(target: any, source: any): void {
  if (!source || typeof source !== 'object' || Array.isArray(source)) return;
  for (const key of Object.keys(source)) {
    const sv = source[key];
    if (key === 'stat_data' && sv && typeof sv === 'object' && !Array.isArray(sv)) {
      deepMergeStatDataLayer(target, sv);
      continue;
    }
    const tv = target[key];
    if (sv && typeof sv === 'object' && !Array.isArray(sv) && tv && typeof tv === 'object' && !Array.isArray(tv)) {
      deepMergeStatDataLayer(tv, sv);
    } else {
      target[key] = sv;
    }
  }
}

/**
 * 将 `stat_data.stat_data`（及更深一层同名嵌套）合并进当前层并删除子 `stat_data`，避免双份 世界/主角。
 */
export function flattenNestedStatDataInStatData(statData: any): boolean {
  if (!statData || typeof statData !== 'object' || Array.isArray(statData)) return false;
  let changed = false;
  while (Object.prototype.hasOwnProperty.call(statData, 'stat_data')) {
    const inner = statData.stat_data;
    if (!inner || typeof inner !== 'object' || Array.isArray(inner)) break;
    deepMergeStatDataLayer(statData, inner);
    delete statData.stat_data;
    changed = true;
  }
  return changed;
}

/** 只应出现在 `主角` 下的字段名（与 stat_data 根上的 世界/背包… 区分） */
export const HERO_FIELD_KEYS_AT_STAT_ROOT: readonly string[] = [
  '姓名',
  '状态',
  '生命值',
  '魔力值',
  '魔人化',
  '核心属性',
  '战斗风格',
  '风格阶位',
  '装备栏',
  '行动预判',
  'DT Gauge',
];

const HERO_ROOT_PATH_HEAD = new Set(HERO_FIELD_KEYS_AT_STAT_ROOT);

/**
 * 与 Dark MVU schema 中 `主角` 顶层字段顺序一致（仅影响 Object.keys 顺序，便于阅读与 diff）。
 * 解决：`{ ...主角, 战斗风格: x }` 或从根收拢字段时，新出现的 `状态` 被追加到末尾，看起来像「跑到行动预判下面」。
 */
export const CANONICAL_HERO_TOP_LEVEL_KEYS: readonly string[] = [
  '姓名',
  '状态',
  '生命值',
  '魔力值',
  'DT Gauge',
  '魔人化',
  '核心属性',
  '战斗风格',
  '风格阶位',
  '装备栏',
  '行动预判',
];

export function normalizeHeroObjectFieldOrder(hero: any): Record<string, unknown> {
  if (!hero || typeof hero !== 'object' || Array.isArray(hero)) return hero;
  const src = hero as Record<string, unknown>;
  const out: Record<string, unknown> = {};
  for (const k of CANONICAL_HERO_TOP_LEVEL_KEYS) {
    if (Object.prototype.hasOwnProperty.call(src, k)) {
      out[k] = src[k];
    }
  }
  for (const k of Object.keys(src)) {
    if (!CANONICAL_HERO_TOP_LEVEL_KEYS.includes(k)) {
      out[k] = src[k];
    }
  }
  return out;
}

/**
 * 若 stat_data 根上存在上述键，则合并进 `stat_data.主角` 并从根上删除。
 * @returns 是否发生了修改（仅反映「根上误写字段」是否被收拢；主角键序会始终规范化）
 */
export function promoteStrayHeroFieldsInStatData(statData: any): boolean {
  if (!statData || typeof statData !== 'object' || Array.isArray(statData)) return false;
  let changed = false;
  const prevHero = statData.主角;
  const nextHero =
    prevHero && typeof prevHero === 'object' && !Array.isArray(prevHero) ? { ...prevHero } : ({} as Record<string, unknown>);

  for (const key of HERO_FIELD_KEYS_AT_STAT_ROOT) {
    if (!Object.prototype.hasOwnProperty.call(statData, key)) continue;
    nextHero[key] = statData[key];
    delete statData[key];
    changed = true;
  }
  if (changed) {
    statData.主角 = nextHero;
  }
  if (statData.主角 && typeof statData.主角 === 'object' && !Array.isArray(statData.主角)) {
    statData.主角 = normalizeHeroObjectFieldOrder(statData.主角);
  }
  return changed;
}

/**
 * 处理 MVU 消息变量表：先展开嵌套 stat_data，再把根上误写的主角字段收拢到 `主角`。
 */
export function promoteStrayHeroFieldsInMvuVariables(mvu: any): boolean {
  if (!mvu?.stat_data || typeof mvu.stat_data !== 'object') return false;
  let c = flattenNestedStatDataInStatData(mvu.stat_data);
  c = promoteStrayHeroFieldsInStatData(mvu.stat_data) || c;
  return c;
}

/**
 * 将 MVU 解析出的 _.set 等命令路径从根级主角字段改写为 `主角.xxx`，减少写入错位。
 */
export function rewriteParsedCommandsHeroRootPaths(commands: any[] | undefined): void {
  if (!commands || !Array.isArray(commands)) return;
  for (const c of commands) {
    if (!c || typeof c !== 'object') continue;
    const t = c.type;
    if (t === 'set' || t === 'insert' || t === 'add' || t === 'delete' || t === 'move') {
      const a0 = c.args?.[0];
      if (typeof a0 !== 'string' || !a0) continue;
      if (a0.startsWith('主角.')) continue;
      const head = a0.split('.')[0] ?? '';
      if (!HERO_ROOT_PATH_HEAD.has(head)) continue;
      c.args[0] = `主角.${a0}`;
      if (t === 'move' && typeof c.args?.[1] === 'string') {
        const a1 = c.args[1];
        if (!a1.startsWith('主角.')) {
          const h1 = a1.split('.')[0] ?? '';
          if (HERO_ROOT_PATH_HEAD.has(h1)) c.args[1] = `主角.${a1}`;
        }
      }
    }
  }
}
